begin;
create table if not exists public.project_region_sources(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,development_id uuid not null references public.developments(id) on delete cascade,category text not null check(category in('mobility','education','health','services','leisure','demand','competition','price_m2','demographics','infrastructure')),title text not null,publisher text not null,source_url text not null,summary text not null,reference_date date not null,valid_until date not null,review_status text not null default 'pending' check(review_status in('pending','verified','rejected','expired')),created_by uuid not null references public.profiles(id),reviewed_by uuid references public.profiles(id),review_note text,reviewed_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),check(valid_until>=reference_date));
create index if not exists project_region_sources_current_idx on public.project_region_sources(organization_id,development_id,review_status,valid_until,category);
create table if not exists public.project_region_source_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,development_id uuid not null references public.developments(id) on delete cascade,source_id uuid not null references public.project_region_sources(id) on delete cascade,actor_id uuid not null references public.profiles(id),event_type text not null check(event_type in('created','verified','rejected')),note text not null,created_at timestamptz not null default now());
alter table public.project_region_sources enable row level security;alter table public.project_region_source_events enable row level security;drop policy if exists project_region_sources_scope on public.project_region_sources;create policy project_region_sources_scope on public.project_region_sources for select to authenticated using(organization_id=(select public.current_organization_id()));drop policy if exists project_region_source_events_scope on public.project_region_source_events;create policy project_region_source_events_scope on public.project_region_source_events for select to authenticated using(organization_id=(select public.current_organization_id()));revoke all on public.project_region_sources,public.project_region_source_events from anon;revoke insert,update,delete on public.project_region_sources,public.project_region_source_events from authenticated;grant select on public.project_region_sources,public.project_region_source_events to authenticated;
create or replace function public.sync_project_region_source_register(p_organization_id uuid,p_development_id uuid)returns void language plpgsql security definer set search_path='' as $$begin update public.project_region_sources set review_status='expired',updated_at=now()where organization_id=p_organization_id and development_id=p_development_id and review_status='verified'and valid_until<current_date;update public.project_intelligence_profiles set source_register=coalesce((select jsonb_agg(jsonb_build_object('id',s.id,'category',s.category,'title',s.title,'publisher',s.publisher,'url',s.source_url,'summary',s.summary,'referenceDate',s.reference_date,'validUntil',s.valid_until,'verified',true)order by s.category,s.title)from public.project_region_sources s where s.organization_id=p_organization_id and s.development_id=p_development_id and s.review_status='verified'and s.valid_until>=current_date),'[]'::jsonb),onboarding_status=case when onboarding_status='published'then'review_pending'else onboarding_status end,ai_context=coalesce(ai_context,'{}'::jsonb)||jsonb_build_object('safe_to_generate',false,'knowledge_status','regional_sources_changed'),updated_at=now()where organization_id=p_organization_id and development_id=p_development_id;end $$;
create or replace function public.upsert_project_region_source(p_actor_id uuid,p_organization_id uuid,p_development_id uuid,p_source_id uuid,p_payload jsonb)returns jsonb language plpgsql security definer set search_path='' as $$declare actor_role text;target_id uuid;category_value text;url_value text;begin select coalesce(commercial_role,case role when'admin'then'director'else role end)into actor_role from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true;if actor_role not in('director','superintendent','manager')then raise exception 'region_source_actor_forbidden';end if;category_value:=coalesce(p_payload->>'category','');url_value:=trim(coalesce(p_payload->>'sourceUrl',''));if category_value not in('mobility','education','health','services','leisure','demand','competition','price_m2','demographics','infrastructure')or char_length(trim(coalesce(p_payload->>'title','')))<3 or char_length(trim(coalesce(p_payload->>'publisher','')))<2 or url_value!~'^https://[^[:space:]]+$'or char_length(trim(coalesce(p_payload->>'summary','')))<20 or(p_payload->>'referenceDate')::date>current_date or(p_payload->>'validUntil')::date<(p_payload->>'referenceDate')::date then raise exception 'region_source_invalid';end if;if not exists(select 1 from public.developments where id=p_development_id and organization_id=p_organization_id)then raise exception 'region_source_development_invalid';end if;if p_source_id is null then insert into public.project_region_sources(organization_id,development_id,category,title,publisher,source_url,summary,reference_date,valid_until,created_by)values(p_organization_id,p_development_id,category_value,trim(p_payload->>'title'),trim(p_payload->>'publisher'),url_value,trim(p_payload->>'summary'),(p_payload->>'referenceDate')::date,(p_payload->>'validUntil')::date,p_actor_id)returning id into target_id;else update public.project_region_sources set category=category_value,title=trim(p_payload->>'title'),publisher=trim(p_payload->>'publisher'),source_url=url_value,summary=trim(p_payload->>'summary'),reference_date=(p_payload->>'referenceDate')::date,valid_until=(p_payload->>'validUntil')::date,review_status='pending',reviewed_by=null,reviewed_at=null,review_note=null,updated_at=now()where id=p_source_id and organization_id=p_organization_id and development_id=p_development_id returning id into target_id;end if;if target_id is null then raise exception 'region_source_not_found';end if;insert into public.project_region_source_events(organization_id,development_id,source_id,actor_id,event_type,note)values(p_organization_id,p_development_id,target_id,p_actor_id,'created','Fonte submetida para revisão humana');perform public.sync_project_region_source_register(p_organization_id,p_development_id);return jsonb_build_object('sourceId',target_id,'reviewStatus','pending','automaticClaimGeneration',false,'auditable',true);end $$;
create or replace function public.review_project_region_source(p_actor_id uuid,p_organization_id uuid,p_source_id uuid,p_status text,p_note text)returns jsonb language plpgsql security definer set search_path='' as $$declare actor_role text;target public.project_region_sources;begin select coalesce(commercial_role,case role when'admin'then'director'else role end)into actor_role from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true;if actor_role not in('director','superintendent')then raise exception 'region_source_review_forbidden';end if;if p_status not in('verified','rejected')or char_length(trim(coalesce(p_note,'')))<10 then raise exception 'region_source_review_invalid';end if;select * into target from public.project_region_sources where id=p_source_id and organization_id=p_organization_id for update;if target.id is null then raise exception 'region_source_not_found';end if;if p_status='verified'and target.valid_until<current_date then raise exception 'region_source_expired';end if;update public.project_region_sources set review_status=p_status,reviewed_by=p_actor_id,reviewed_at=now(),review_note=trim(p_note),updated_at=now()where id=target.id;insert into public.project_region_source_events(organization_id,development_id,source_id,actor_id,event_type,note)values(p_organization_id,target.development_id,target.id,p_actor_id,p_status,trim(p_note));perform public.sync_project_region_source_register(p_organization_id,target.development_id);return jsonb_build_object('sourceId',target.id,'reviewStatus',p_status,'validUntil',target.valid_until,'humanReviewed',true,'auditable',true);end $$;
revoke all on function public.sync_project_region_source_register(uuid,uuid),function public.upsert_project_region_source(uuid,uuid,uuid,uuid,jsonb),function public.review_project_region_source(uuid,uuid,uuid,text,text)from public,anon,authenticated;grant execute on function public.sync_project_region_source_register(uuid,uuid),function public.upsert_project_region_source(uuid,uuid,uuid,uuid,jsonb),function public.review_project_region_source(uuid,uuid,uuid,text,text)to service_role;
commit;
